function renderStatic(){
  const ui = UI[state.lang];
  document.getElementById('homeQuestions').innerHTML = ui.homeQuestions.map(homeQuestionHTML).join('');
  document.getElementById('routeCards').innerHTML = ROUTES.map(cardHTML).join('');
  document.getElementById('bachCards').innerHTML = BACH.map(cardHTML).join('');
  document.getElementById('fpCards').innerHTML = FP_CARDS.map(cardHTML).join('');
  document.getElementById('universityCards').innerHTML = UNIVERSITY_CARDS.map(cardHTML).join('');
  document.getElementById('masterCards').innerHTML = MASTER_CARDS.map(cardHTML).join('');
  document.getElementById('ponderationLinks').innerHTML = sourceLinks(['ciug-admision','ciug-ponderaciones-2026','nerta']);
  renderFilters(); renderTags(); renderAreaButtons(); renderSourceFilters(); renderSources(state.sourceFilter); renderQuestionChips(); renderAdventure(); bindDynamicRoutes();
}
function bindDynamicRoutes(){ document.querySelectorAll('[data-route]').forEach(link => { if(link.dataset.bound==='1') return; link.dataset.bound='1'; link.addEventListener('click', e => { e.preventDefault(); routeTo(link.dataset.route); }); }); }

function renderFilters(){
  const ui=UI[state.lang];
  const typeSelect=document.getElementById('studyTypeFilter');
  const familySelect=document.getElementById('familyFilter');
  if(!typeSelect||!familySelect) return;
  const currentType=typeSelect.value||'all';
  const currentFamily=familySelect.value||'all';
  typeSelect.innerHTML=STUDY_TYPES.map(t=>`<option value="${t.id}">${escapeHTML(pick(t))}</option>`).join('');
  familySelect.innerHTML=`<option value="all">${escapeHTML(ui.anyFamilyOption||ui.allOption||'Todas')}</option>`+FP_FAMILIES.map(f=>`<option value="${escapeHTML(f)}">${escapeHTML(f)}</option>`).join('');
  typeSelect.value=[...STUDY_TYPES.map(t=>t.id)].includes(currentType)?currentType:'all';
  familySelect.value=[...FP_FAMILIES,'all'].includes(currentFamily)?currentFamily:'all';
  [typeSelect,familySelect,document.getElementById('cityFilter'),document.getElementById('centerFilter')].forEach(el=>{
    if(!el || el.dataset.bound==='1') return;
    el.dataset.bound='1'; el.addEventListener('change',()=>runStudySearch(document.getElementById('studySearch').value)); el.addEventListener('input',()=>{ if(el.tagName==='INPUT' && document.getElementById('studySearch').value.trim()) runStudySearch(document.getElementById('studySearch').value); });
  });
}

function renderTags(){ const ui=UI[state.lang]; const box=document.getElementById('quickTags'); box.innerHTML=ui.quickTags.map(t=>`<button type="button" data-study-tag="${escapeHTML(t)}">${escapeHTML(t)}</button>`).join(''); box.querySelectorAll('button').forEach(btn=>btn.addEventListener('click',()=>{ document.getElementById('studySearch').value=btn.dataset.studyTag; runStudySearch(btn.dataset.studyTag); })); }
function runStudySearch(query){ const ui=UI[state.lang]; const out=document.getElementById('studyResults'); const clean=(query||'').trim(); if(!clean){ out.innerHTML=`<div class="warning-box">${escapeHTML(ui.emptySearch)}</div>`; return; } const programs=findPrograms(clean); const areas=findStudy(clean); if(!programs.length && !areas.length){ out.innerHTML=officialFallbackHTML(clean); return; } const approximate = programs.length && normalize(programs[0].name)!==normalize(clean) && !normalize(programs[0].name).includes(normalize(clean)); out.innerHTML = programs.map((p,i)=>programHTML(p, clean, i===0 && approximate)).join('') + areas.map(area=>studyAreaHTML(area, clean)).join(''); }
function renderAreaButtons(){ const box=document.getElementById('areaButtons'); box.innerHTML=STUDY_AREAS.map(area=>`<button type="button" data-area="${area.id}">${escapeHTML(pick(area.title))}</button>`).join(''); box.querySelectorAll('button').forEach(btn=>btn.addEventListener('click',()=>{ const area=STUDY_AREAS.find(a=>a.id===btn.dataset.area); document.getElementById('areaOutput').innerHTML=studyAreaHTML(area,pick(area.title)); })); }
function renderSourceFilters(){ const ui=UI[state.lang]; const filters=[['all',ui.filters.all],['itinerarios',ui.filters.itinerarios],['fp',ui.filters.fp],['universidad',ui.filters.universidad],['galicia',ui.filters.galicia],['artes',ui.filters.artes],['legal',ui.filters.legal]]; const box=document.getElementById('sourceFilters'); box.innerHTML=filters.map(([id,label])=>`<button class="chip ${state.sourceFilter===id?'active':''}" data-filter="${id}">${escapeHTML(label)}</button>`).join(''); box.querySelectorAll('[data-filter]').forEach(btn=>btn.addEventListener('click',()=>{ state.sourceFilter=btn.dataset.filter; renderSourceFilters(); renderSources(state.sourceFilter); })); }
function renderSources(filter){ const ui=UI[state.lang]; const list=SOURCES.filter(s=>filter==='all'||s.category.includes(filter)); document.getElementById('sourceCards').innerHTML=list.map(s=>`<article class="content-card"><h2>${escapeHTML(pick(s.title))}</h2><p>${escapeHTML(pick(s.use))}</p><div class="badges">${s.category.map(cat=>`<span class="badge">${escapeHTML(ui.filters[cat]||cat)}</span>`).join('')}</div><a class="button primary" href="${s.url}" target="_blank" rel="noopener noreferrer">${escapeHTML(ui.openSource)}</a></article>`).join(''); }
function renderQuestionChips(){ const box=document.getElementById('questionChips'); box.innerHTML=UI[state.lang].chatSuggestions.map(q=>`<button class="question-chip" type="button">${escapeHTML(q)}</button>`).join(''); box.querySelectorAll('.question-chip').forEach(btn=>btn.addEventListener('click',()=>{ document.getElementById('chatInput').value=btn.textContent; document.getElementById('chatForm').dispatchEvent(new Event('submit')); })); }


