function adventureText(start, goal){
  const lang=state.lang;
  const base={
    gl:'Ruta orientativa:', es:'Ruta orientativa:', en:'Indicative route:', pt:'Rota orientativa:'
  }[lang]||'Ruta orientativa:';
  let text=''; let sources=['educagob-eso','todofp','qedu','ciug-admision'];
  if(start==='eso_titulo'&&goal==='bach') text= lang==='es'?'ESO con título → Bachillerato. Después podrás orientar la modalidad según estudios futuros.':'ESO con título → Bacharelato. Despois poderás orientar a modalidade segundo os estudos futuros.';
  else if(start==='eso_titulo'&&goal==='gm') text= lang==='es'?'ESO con título → ciclo formativo de grado medio. Consulta familia profesional, ciclo, centro y plazas.':'ESO con título → ciclo formativo de grao medio. Consulta familia profesional, ciclo, centro e prazas.';
  else if((start==='bach'||start==='gm')&&goal==='gs') text= lang==='es'?'Bachillerato o FP de grado medio → ciclo formativo de grado superior. Revisa acceso, admisión y oferta real.':'Bacharelato ou FP de grao medio → ciclo formativo de grao superior. Revisa acceso, admisión e oferta real.';
  else if((start==='bach'||start==='gs')&&goal==='uni') text= lang==='es'?'Bachillerato → PAU/ABAU → universidad, o FP superior → universidad. Si necesitas nota alta, revisa ponderaciones CIUG y notas de corte.':'Bacharelato → PAU/ABAU → universidade, ou FP superior → universidade. Se precisas nota alta, revisa ponderacións CIUG e notas de corte.';
  else if(goal==='regulada') { text= lang==='es'?'Identifica primero la profesión exacta. Algunas vías exigen grado concreto y otras grado + máster habilitante. Comprueba siempre RUCT y normativa oficial.' : 'Identifica primeiro a profesión exacta. Algunhas vías esixen grao concreto e outras grao + máster habilitante. Comproba sempre RUCT e normativa oficial.'; sources=['ruct','ruct-faq','rd-822-2021','qedu']; }
  else if(goal==='artes') { text= lang==='es'?'Revisa si la meta es grado universitario, enseñanza artística superior, ciclo de Artes Plásticas y Diseño o enseñanza profesional. Puede haber prueba específica.':'Revisa se a meta é grao universitario, ensinanza artística superior, ciclo de Artes Plásticas e Deseño ou ensinanza profesional. Pode haber proba específica.'; sources=['infoartisticas-ensenanzas','educagob-bach-organizacion']; }
  else if(goal==='empleo') { text= lang==='es'?'Busca una titulación vinculada a un perfil profesional y revisa datos oficiales de mercado laboral por titulación u ocupación en SEPE.':'Busca unha titulación vinculada a un perfil profesional e revisa datos oficiais de mercado laboral por titulación ou ocupación no SEPE.'; sources=['sepe-titulaciones','sepe-ocupaciones','todofp']; }
  else text= lang==='es'?'Selecciona una ruta compatible y comprueba requisitos de acceso, oferta real y fuentes oficiales antes de decidir matrícula.':'Selecciona unha ruta compatible e comproba requisitos de acceso, oferta real e fontes oficiais antes de decidir matrícula.';
  return `<h3>${escapeHTML(base)}</h3><p>${escapeHTML(text)}</p>${sourceLinks(sources)}`;
}
function renderAdventure(){
  const ui=UI[state.lang];
  const startBox=document.getElementById('adventureStartOptions');
  const goalBox=document.getElementById('adventureGoalOptions');
  if(!startBox||!goalBox) return;
  startBox.innerHTML=ADVENTURE_STARTS.map(o=>`<button type="button" data-start="${o.id}" class="${adventureState.start===o.id?'active':''}">${escapeHTML(pick(o))}</button>`).join('');
  goalBox.innerHTML=ADVENTURE_GOALS.map(o=>`<button type="button" data-goal="${o.id}" class="${adventureState.goal===o.id?'active':''}">${escapeHTML(pick(o))}</button>`).join('');
  startBox.querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>{ adventureState.start=b.dataset.start; renderAdventure(); }));
  goalBox.querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>{ adventureState.goal=b.dataset.goal; renderAdventure(); }));
  const result=document.getElementById('adventureResult');
  result.innerHTML = adventureState.start&&adventureState.goal ? adventureText(adventureState.start, adventureState.goal) : `<p>${escapeHTML(ui.adventureEmpty)}</p>`;
}

function reply(text, sources){ return `<p>${text}</p>${sourceLinks(sources)}`; }
function botAnswer(raw){ const q=normalize(raw); const programMatches=findPrograms(raw); const areaMatches=findStudy(raw); const lang=state.lang; const ui=UI[lang];
  if(programMatches.length && programMatches[0].score>.62){ return programHTML(programMatches[0], raw, normalize(programMatches[0].name)!==normalize(raw) && !normalize(programMatches[0].name).includes(normalize(raw))); }
  if(q.includes('eso')) return reply(lang==='es'?'Después de la ESO debes distinguir si el alumnado tiene o no el título. Con el título se abren Bachillerato, FP de grado medio, enseñanzas artísticas y deportivas de grado medio según requisitos. Sin título, existen vías condicionadas a pruebas de acceso, edad o educación de personas adultas.':lang==='en'?'After lower secondary education, you first need to distinguish whether the student has the graduation certificate. With the certificate, Baccalaureate, intermediate VET and some arts and sports routes become available; without it, there are conditional routes linked to access tests, age or adult education.':lang==='pt'?'Depois da ESO, é preciso distinguir se o aluno tem ou não o título. Com o título, abrem-se vias como Bacharelato, FP de grau médio e algumas vias artísticas e desportivas; sem ele, existem vias condicionadas.':'Despois da ESO hai que distinguir se o alumnado ten ou non o título. Co título ábrense Bacharelato, FP de grao medio, ensinanzas artísticas e deportivas de grao medio segundo requisitos. Sen título, existen vías condicionadas a probas de acceso, idade ou educación de persoas adultas.', ['educagob-eso','todofp']);
  if(q.includes('bachillerato')||q.includes('bacharelato')) return reply(lang==='es'?'La elección de Bachillerato debe hacerse según el estudio futuro. Ciencias y Tecnología suele ser la vía más habitual para salud e ingenierías; Humanidades y Ciencias Sociales, para derecho, educación, empresa o historia; y Artes, para enseñanzas artísticas y grados afines.':lang==='en'?'Baccalaureate choice should be made according to the future study plan. Science and Technology is usually the most common route for health fields and engineering; Humanities and Social Sciences for law, education, business or history; and Arts for arts education and related degrees.':lang==='pt'?'A escolha do Bacharelato deve ser feita segundo o estudo futuro. Ciências e Tecnologia costuma ser a via mais comum para saúde e engenharias; Humanidades e Ciências Sociais para direito, educação, empresa ou história; e Artes para ensino artístico e cursos afins.':'A elección de Bacharelato debe facerse segundo o estudo futuro. Ciencias e Tecnoloxía adoita ser a vía máis habitual para saúde e enxeñarías; Humanidades e Ciencias Sociais, para dereito, educación, empresa ou historia; e Artes, para ensinanzas artísticas e graos afíns.', ['educagob-bach-organizacion','ciug-ponderaciones-2026']);
  if(q.includes('ponder')) return reply(lang==='es'?'Para Galicia, las ponderaciones oficiales se consultan en la CIUG. ITINERA puede orientarte sobre qué materias revisar, pero el valor oficial por grado debe comprobarse en la tabla vigente del año de acceso.':lang==='en'?'In Galicia, official subject weightings are checked in CIUG. ITINERA can guide you on which subjects to review, but the official value for each degree must be checked in the current table for the relevant access year.':lang==='pt'?'Na Galiza, as ponderações oficiais consultam-se na CIUG. A ITINERA pode orientar sobre as disciplinas a rever, mas o valor oficial por curso deve ser verificado na tabela vigente do ano de acesso.':'Para Galicia, as ponderacións oficiais consúltanse na CIUG. ITINERA pode orientarte sobre que materias revisar, pero o valor oficial por grao debe comprobarse na táboa vixente do ano de acceso.', ['ciug-admision','ciug-ponderaciones-2026','nerta']);
  if(q.includes('fp')||q.includes('formacion profesional')||q.includes('formación profesional')||q.includes('ciclo')) return reply(lang==='es'?'Para FP conviene consultar dos niveles: TodoFP para la estructura estatal y la Xunta de Galicia para la oferta real en Galicia. En la Xunta debes revisar oferta, buscador de ciclos y buscador de centros.':lang==='en'?'For VET, it is useful to check two levels: TodoFP for the national structure and Xunta de Galicia for the actual provision in Galicia. In the Xunta portal, review the provision, programme search tool and centre search tool.':lang==='pt'?'Para a FP, convém consultar dois níveis: o TodoFP para a estrutura estatal e a Xunta de Galicia para a oferta real na Galiza. Na Xunta, deves rever a oferta, a pesquisa de ciclos e a pesquisa de centros.':'Para FP convén consultar dous niveis: TodoFP para a estrutura estatal e a Xunta de Galicia para a oferta real en Galicia. Na Xunta debes revisar oferta, buscador de ciclos e buscador de centros.', ['todofp','xunta-fp-oferta','xunta-fp-ciclos','xunta-fp-centros']);
  if(q.includes('oficial')||q.includes('ruct')) return reply(lang==='es'?'Si quieres comprobar si un grado o un máster es oficial, la referencia clave es el RUCT. QEDU sirve para explorar qué estudiar y dónde, pero la verificación administrativa corresponde al RUCT.':lang==='en'?'If you want to check whether a degree or master’s programme is official, the key reference is RUCT. QEDU is useful to explore what and where to study, but administrative verification belongs to RUCT.':lang==='pt'?'Se quiseres verificar se um curso ou mestrado é oficial, a referência-chave é o RUCT. O QEDU é útil para explorar o que estudar e onde, mas a verificação administrativa cabe ao RUCT.':'Se queres comprobar se un grao ou un máster é oficial, a referencia clave é o RUCT. QEDU serve para explorar que estudar e onde, pero a verificación administrativa correspóndelle ao RUCT.', ['qedu','ruct']);
  if(q.includes('habilitante')||q.includes('profesion regulada')||q.includes('profesión regulada')||q.includes('master habilitante')||q.includes('máster habilitante')) return reply(lang==='es'?'Un máster habilitante es un máster universitario oficial que habilita para una profesión regulada cuando así lo establece la normativa. Algunas vías frecuentes son Arquitectura, abogacía y procura, Psicología General Sanitaria, profesorado de Secundaria y varias ingenierías. La comprobación final debe hacerse en el RUCT y en la normativa correspondiente.':lang==='en'?'An enabling master’s degree is an official university master’s programme that qualifies a person for a regulated profession when this is established by law. Frequent routes include Architecture, legal practice, General Health Psychology, secondary teaching and several branches of engineering. Final verification should be done in RUCT and in the relevant regulation.':lang==='pt'?'Um mestrado habilitante é um mestrado universitário oficial que habilita para uma profissão regulada quando a norma assim o estabelece. Entre as vias frequentes estão Arquitetura, advocacia e procura, Psicologia Geral Sanitária, docência no ensino secundário e várias engenharias. A verificação final deve ser feita no RUCT e na norma correspondente.':'Un máster habilitante é un máster universitario oficial que habilita para unha profesión regulada cando así o establece a normativa. Entre as vías frecuentes están Arquitectura, avogacía e procura, Psicoloxía Xeral Sanitaria, profesorado de Secundaria e varias enxeñarías. A comprobación final debe facerse no RUCT e na normativa correspondente.', ['ruct-faq','rd-822-2021','ruct']);
  if(areaMatches.length){ return areaMatches.map(a=>`<p><strong>${escapeHTML(pick(a.title))}.</strong> ${escapeHTML(pick(a.route))}</p><p><strong>${escapeHTML(ui.subjectsLabel)}:</strong> ${a.subjects.map(escapeHTML).join(', ')}.</p><p><strong>${escapeHTML(ui.cautionLabel)}:</strong> ${escapeHTML(pick(a.caution))}</p>${sourceLinks(a.sources)}`).join(''); }
  return reply(lang==='es'?'No puedo dar una respuesta cerrada sin riesgo de simplificar demasiado. Utiliza la sección correspondiente de la herramienta y revisa las fuentes oficiales enlazadas para obtener la comprobación final.':lang==='en'?'I cannot give a closed answer without oversimplifying. Please use the relevant section of the tool and review the linked official sources for final verification.':lang==='pt'?'Não posso dar uma resposta fechada sem simplificar demasiado. Usa a secção correspondente da ferramenta e consulta as fontes oficiais para a verificação final.':'Non podo dar unha resposta pechada sen simplificar demasiado. Usa a sección correspondente da ferramenta e revisa as fontes oficiais enlazadas para obter a comprobación final.', ['educagob-eso','todofp','ciug-admision','qedu','ruct']);
}
