function routeTo(id){ const target=id||'inicio'; document.querySelectorAll('.view').forEach(v=>v.classList.remove('active-view')); const view=document.getElementById(target)||document.getElementById('inicio'); view.classList.add('active-view'); document.querySelectorAll('.main-nav [data-route]').forEach(a=>a.classList.toggle('active', a.dataset.route===target)); window.location.hash=target; view.focus({preventScroll:true}); document.getElementById('mainNav').classList.remove('open'); document.getElementById('navToggle').setAttribute('aria-expanded','false'); }
