function initChat(){ resetChat(); document.getElementById('chatForm').addEventListener('submit', ev=>{ ev.preventDefault(); const input=document.getElementById('chatInput'); const text=input.value.trim(); if(!text) return; addMsg('user', `<p>${escapeHTML(text)}</p>`); addMsg('bot', botAnswer(text)); input.value=''; }); }
