function initNavToggle(){ const btn=document.getElementById('navToggle'); const nav=document.getElementById('mainNav'); btn.addEventListener('click', ()=>{ const isOpen=nav.classList.toggle('open'); btn.setAttribute('aria-expanded', String(isOpen)); }); }
function openModal(id){ document.getElementById('modalBackdrop').hidden=false; document.getElementById(id).hidden=false; document.body.style.overflow='hidden'; }
