function initModals(){ document.querySelectorAll('[data-modal-open]').forEach(btn=>btn.addEventListener('click',()=>openModal(btn.dataset.modalOpen))); document.querySelectorAll('[data-modal-close]').forEach(btn=>btn.addEventListener('click',closeModal)); document.getElementById('modalBackdrop').addEventListener('click',closeModal); document.addEventListener('keydown',e=>{ if(e.key==='Escape') closeModal(); }); }

document.addEventListener('DOMContentLoaded', ()=>{ applyUIText(); renderStatic(); initSearch(); initChat(); initLanguage(); initNavToggle(); initRouter(); initModals(); });

