const LOCAL_AVAILABILITY = {
  'Técnico en Carpintería y Mueble': {
    mode:'dynamic',
    provinces:{
      'A Coruña':['Consultar oferta oficial da Xunta para centros e prazas actualizadas.'],
      'Lugo':['Consultar oferta oficial da Xunta para centros e prazas actualizadas.'],
      'Ourense':['Consultar oferta oficial da Xunta para centros e prazas actualizadas.'],
      'Pontevedra':['Consultar oferta oficial da Xunta para centros e prazas actualizadas.']
    }
  }
};

getFilters = function(){
  return {
    type: document.getElementById('studyTypeFilter')?.value || 'all',
    family: document.getElementById('familyFilter')?.value || 'all',
    residence: (document.getElementById('residenceFilter')?.value || '').trim()
  };
}

findPrograms = function(query){
  const q=normalize(query||'');
  const f=getFilters();
  return PROGRAM_CATALOG.map(item=>{
    const hay=[item.name,item.family,...(item.keywords||[])].join(' ');
    const exact=q && (normalize(hay).includes(q) || q.includes(normalize(item.name)));
    const best=q ? Math.max(...[item.name,item.family,...(item.keywords||[])].map(x=>similarity(q,x))) : .55;
    let score=exact?1.25:best;
    if(f.type!=='all' && item.type!==f.type) score-=.55;
    if(f.family!=='all' && normalize(item.family)!==normalize(f.family)) score-=.4;
    if(!q && (f.type!=='all'||f.family!=='all')) score+=.2;
    return {...item, score};
  }).filter(x=>x.score>.38).sort((a,b)=>b.score-a.score).slice(0,8);
}

renderFilters = function(){
  const ui=UI[state.lang];
  const typeSelect=document.getElementById('studyTypeFilter');
  const familySelect=document.getElementById('familyFilter');
  if(!typeSelect||!familySelect) return;
  const currentType=typeSelect.value||'all';
  const currentFamily=familySelect.value||'all';
  typeSelect.innerHTML=STUDY_TYPES.map(t=>`<option value="${t.id}">${escapeHTML(pick(t))}</option>`).join('');
  familySelect.innerHTML=`<option value="all">${escapeHTML(ui.anyFamilyOption||ui.allOption||'Todas')}</option>`+FP_FAMILIES.map(f=>`<option value="${escapeHTML(f)}">${escapeHTML(f)}</option>`).join('');
  typeSelect.value=[...STUDY_TYPES.map(t=>t.id)].includes(currentType)?currentType:'all';
  familySelect.value=[...FP_FAMILIES,'all'].includes(currentFamily)?currentFamily:'all';
  [typeSelect,familySelect,document.getElementById('residenceFilter')].forEach(el=>{
    if(!el || el.dataset.bound==='1') return;
    el.dataset.bound='1';
    const handler=()=>runStudySearch(document.getElementById('studySearch').value);
    el.addEventListener('change',handler); el.addEventListener('input',()=>{ if(el.id!=='residenceFilter'||document.getElementById('studySearch').value.trim()) handler(); });
  });
}

function availabilityHTML(item){
  const ui=UI[state.lang];
  const av=item.availability || LOCAL_AVAILABILITY[item.name];
  const residence=getFilters().residence;
  if(!av){
    return `<div class="warning-box"><strong>${escapeHTML(ui.availabilityTitle)}.</strong> ${escapeHTML(ui.noVerifiedCentres)}</div>`;
  }
  const rows=PROVINCES_GALICIA.map(p=>{
    const centres=(av.provinces&&av.provinces[p]) ? av.provinces[p] : [ui.noVerifiedCentres];
    return `<tr><th>${escapeHTML(p)}</th><td>${centres.map(c=>`<div>${escapeHTML(c)}</div>`).join('')}</td></tr>`;
  }).join('');
  return `<section class="availability-block"><h4>${escapeHTML(ui.availabilityTitle)}</h4>${residence?`<p><strong>${state.lang==='es'?'Localidad de residencia indicada':state.lang==='en'?'Home locality entered':state.lang==='pt'?'Localidade indicada':'Localidade indicada'}:</strong> ${escapeHTML(residence)}. ${state.lang==='es'?'Cuando el backend oficial esté activo, se priorizarán las ofertas más cercanas.':state.lang==='en'?'When the official backend is active, nearby offers will be prioritised.':state.lang==='pt'?'Quando o backend oficial estiver ativo, as ofertas mais próximas serão priorizadas.':'Cando o backend oficial estea activo, priorizaranse as ofertas máis próximas.'}</p>`:''}<table class="availability-table"><thead><tr><th>${escapeHTML(ui.provinceLabel)}</th><th>${escapeHTML(ui.centresLabel)}</th></tr></thead><tbody>${rows}</tbody></table></section>`;
}

programHTML = function(item, query, approximate=false){
  const ui=UI[state.lang];
  const reportId=`report-${Math.random().toString(36).slice(2)}`;
  return `<article class="result-card" id="${reportId}"><h3>${escapeHTML(item.name)}</h3>${approximate?`<div class="suggestion-line">${state.lang==='es'?'Quizás quisiste decir':state.lang==='en'?'Did you mean':state.lang==='pt'?'Talvez quisesses dizer':'Quizais quixeches dicir'}: ${escapeHTML(item.name)}</div>`:''}<div class="program-meta"><div><strong>${escapeHTML(ui.typeFilterLabel)}</strong><span>${escapeHTML(pick(STUDY_TYPES.find(t=>t.id===item.type)||{gl:item.type}))}</span></div><div><strong>${escapeHTML(ui.familyFilterLabel)}</strong><span>${escapeHTML(item.family)}</span></div></div><p><strong>Itinerario:</strong> ${escapeHTML(item.route)}</p><p><strong>${escapeHTML(ui.subjectsLabel)}:</strong> ${escapeHTML(item.subjects.join(' · '))}</p><p><strong>Máster habilitante/profesión regulada:</strong> ${escapeHTML(item.habilitante)}</p><p><strong>Demanda, inserción o nicho profesional:</strong> ${escapeHTML(item.labour)}</p>${availabilityHTML(item)}<div class="result-actions"><button type="button" class="button pdf-button" onclick="exportElementPDF('${reportId}','${escapeHTML(item.name).replace(/'/g,'&#039;')}')">${escapeHTML(ui.exportPDF)}</button></div>${sourceLinks(item.sources)}</article>`;
}

async function tryOfficialApi(query){
  const f=getFilters();
  try{
    const params=new URLSearchParams({q:query||'',type:f.type,family:f.family,residence:f.residence,lang:state.lang});
    const res=await fetch(`${OFFICIAL_BACKEND}?${params.toString()}`,{headers:{'Accept':'application/json'}});
    if(!res.ok) return null;
    return await res.json();
  }catch(e){ return null; }
}

runStudySearch = async function(query){
  const ui=UI[state.lang]; const out=document.getElementById('studyResults'); const clean=(query||'').trim(); const f=getFilters();
  const hasFilters=f.type!=='all'||f.family!=='all';
  if(!clean && !hasFilters){ out.innerHTML=`<div class="warning-box">${escapeHTML(ui.emptySearch)}</div>`; return; }
  const programs=findPrograms(clean); const areas=clean?findStudy(clean):[];
  const backend=await tryOfficialApi(clean);
  let html='';
  if(backend && backend.results && backend.results.length){
    html += backend.results.map((p,i)=>programHTML(p, clean || p.name, Boolean(p.suggestion))).join('');
  }
  if(!html){
    if(!programs.length && !areas.length) html=officialFallbackHTML(clean || pick(STUDY_TYPES.find(t=>t.id===f.type)||{gl:'busca por filtros'}));
    else {
      const approximate = clean && programs.length && normalize(programs[0].name)!==normalize(clean) && !normalize(programs[0].name).includes(normalize(clean));
      html = programs.map((p,i)=>programHTML(p, clean || p.name, i===0 && approximate)).join('') + areas.map(area=>studyAreaHTML(area, clean)).join('');
    }
  }
  out.innerHTML=html;
}

officialFallbackHTML = function(query){
  const ui=UI[state.lang];
  return `<article class="result-card"><h3>${escapeHTML(ui.noCardTitle(query))}</h3><p>${escapeHTML(ui.noCardText)}</p><p>${escapeHTML(ui.officialUpdateNote||'')}</p><div class="result-actions"><button type="button" class="button pdf-button" onclick="window.print()">${escapeHTML(ui.exportPDF||'PDF')}</button></div>${sourceLinks(['todofp-familias','todofp-gm','todofp-gs','xunta-fp-oferta','xunta-fp-centros','qedu','ruct','ciug-admision','infoartisticas-ensenanzas','sepe-titulaciones'])}</article>`;
}

function exportElementPDF(elementId,title){
  const el=document.getElementById(elementId); if(!el) return window.print();
  const report=document.createElement('section');
  report.className='print-report';
  report.innerHTML=`<h1>${title||'ITINERA'}</h1>${el.innerHTML}<p class="print-license">ITINERA · Creative Commons CC BY-NC-SA 4.0 · ${LAST_UPDATED}</p>`;
  document.body.appendChild(report);
  document.body.classList.add('printing-report');
  setTimeout(()=>{ window.print(); document.body.classList.remove('printing-report'); report.remove(); },80);
}

function routeBoardHTML(nodes, sources){
  const ui=UI[state.lang];
  return `<div class="route-board">${nodes.map((n,i)=>`<div class="route-node ${i===nodes.length-1?'goal':''}"><strong>${escapeHTML(n.title)}</strong><span>${escapeHTML(n.text||'')}</span></div>`).join('')}</div><div class="board-actions"><button type="button" class="button pdf-button" onclick="exportBoardPDF()">${escapeHTML(ui.exportPDF)}</button></div>${sourceLinks(sources||['educagob-eso','educagob-bach-opciones','ciug-admision'])}`;
}

function currentAdventureGoal(){
  const typed=(document.getElementById('adventureGoalSearch')?.value||'').trim();
  if(typed) return typed;
  const goal=ADVENTURE_GOALS.find(g=>g.id===adventureState.goal);
  return goal ? pick(goal) : '';
}

adventureText = function(start, goal){
  const lang=state.lang; const typed=currentAdventureGoal(); const g=normalize(typed || goal);
  let nodes=[]; let sources=['educagob-eso','educagob-bach-organizacion','ciug-admision','ciug-ponderaciones-2026'];
  const startLabel=pick(ADVENTURE_STARTS.find(s=>s.id===start)||{gl:'Inicio'});
  if(g.includes('arquitect')){
    nodes=[{title:startLabel,text:'Punto de partida'},{title:lang==='es'?'Bachillerato de Ciencias y Tecnología':'Bacharelato de Ciencias e Tecnoloxía',text:'Priorizar Matemáticas II, Física y Dibujo Técnico II'},{title:'ABAU/PAU',text:'Revisar ponderaciones CIUG y notas de corte'},{title:lang==='es'?'Grado vinculado a Arquitectura':'Grao vinculado a Arquitectura',text:'Comprobar denominación oficial en RUCT/QEDU'},{title:lang==='es'?'Máster Universitario en Arquitectura':'Máster Universitario en Arquitectura',text:'Vía habitual de habilitación profesional'}]; sources=['educagob-bach-organizacion','ciug-ponderaciones-2026','qedu','ruct','ruct-faq','rd-822-2021'];
  }else if(g.includes('medicina')){
    nodes=[{title:startLabel,text:'Punto de partida'},{title:lang==='es'?'Bachillerato de Ciencias y Tecnología':'Bacharelato de Ciencias e Tecnoloxía',text:'Biología, Química, Matemáticas II y Física según ponderación'},{title:'ABAU/PAU',text:'Materia 0,2 y nota de corte son decisivas'},{title:lang==='es'?'Grado en Medicina':'Grao en Medicina',text:'Título universitario oficial; revisar QEDU/RUCT'}]; sources=['educagob-bach-organizacion','ciug-ponderaciones-2026','ciug-admision','qedu','ruct'];
  }else if(g.includes('derecho')||g.includes('dereito')||g.includes('abog')){
    nodes=[{title:startLabel,text:'Punto de partida'},{title:lang==='es'?'Bachillerato de Humanidades y Ciencias Sociales':'Bacharelato de Humanidades e Ciencias Sociais',text:'Revisar materias que ponderan para Derecho'},{title:'ABAU/PAU',text:'Consultar CIUG'},{title:lang==='es'?'Grado en Derecho':'Grao en Dereito',text:'Título universitario oficial'},{title:lang==='es'?'Máster habilitante de Abogacía y Procura':'Máster habilitante de Avogacía e Procura',text:'Necesario para esa salida profesional'}]; sources=['ciug-ponderaciones-2026','qedu','ruct','ruct-faq'];
  }else if(g.includes('psicolo')){
    nodes=[{title:startLabel,text:'Punto de partida'},{title:lang==='es'?'Bachillerato según ponderaciones':'Bacharelato segundo ponderacións',text:'Puede combinar materias sociales y biosanitarias'},{title:'ABAU/PAU',text:'Revisar CIUG'},{title:lang==='es'?'Grado en Psicología':'Grao en Psicoloxía',text:'Consultar QEDU/RUCT'},{title:lang==='es'?'Máster en Psicología General Sanitaria si se busca vía sanitaria':'Máster en Psicoloxía Xeral Sanitaria se se busca vía sanitaria',text:'Comprobar normativa y título oficial'}]; sources=['ciug-ponderaciones-2026','qedu','ruct','ruct-faq'];
  }else if(g.includes('fp')||goal==='gs'||goal==='gm'){
    nodes=[{title:startLabel,text:'Punto de partida'},{title:lang==='es'?'Elegir familia profesional':'Elixir familia profesional',text:'Sanidad, Informática, Administración, Madera, etc.'},{title:lang==='es'?'Ciclo de FP':'Ciclo de FP',text:'Grado medio o superior según acceso'},{title:lang==='es'?'Centro y plazas en Galicia':'Centro e prazas en Galicia',text:'Consultar oferta oficial de la Xunta'}]; sources=['todofp','xunta-fp-oferta','xunta-fp-centros'];
  }else{
    nodes=[{title:startLabel,text:'Punto de partida'},{title:lang==='es'?'Elegir vía compatible':'Elixir vía compatible',text:'Bachillerato, FP o enseñanzas específicas'},{title:lang==='es'?'Comprobar requisitos':'Comprobar requisitos',text:'Acceso, admisión, prueba específica o título previo'},{title:typed||pick(ADVENTURE_GOALS.find(g=>g.id===goal)||{gl:'Meta'}),text:'Meta formativa o profesional'}];
  }
  return routeBoardHTML(nodes,sources);
}

renderAdventure = function(){
  const ui=UI[state.lang];
  const startBox=document.getElementById('adventureStartOptions'); const goalBox=document.getElementById('adventureGoalOptions');
  if(!startBox||!goalBox) return;
  startBox.innerHTML=ADVENTURE_STARTS.map(o=>`<button type="button" data-start="${o.id}" class="${adventureState.start===o.id?'active':''}">${escapeHTML(pick(o))}</button>`).join('');
  goalBox.innerHTML=ADVENTURE_GOALS.map(o=>`<button type="button" data-goal="${o.id}" class="${adventureState.goal===o.id?'active':''}">${escapeHTML(pick(o))}</button>`).join('');
  const targetInput=document.getElementById('adventureGoalSearch'); if(targetInput && targetInput.dataset.bound!=='1'){ targetInput.dataset.bound='1'; targetInput.addEventListener('input',()=>renderAdventure()); }
  startBox.querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>{ adventureState.start=b.dataset.start; renderAdventure(); }));
  goalBox.querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>{ adventureState.goal=b.dataset.goal; renderAdventure(); }));
  const result=document.getElementById('adventureResult'); const hasGoal=adventureState.goal || (targetInput&&targetInput.value.trim());
  result.innerHTML = adventureState.start&&hasGoal ? adventureText(adventureState.start, adventureState.goal) : `<p>${escapeHTML(ui.adventureEmpty)}</p>`;
}

function exportBoardPDF(){
  const el=document.getElementById('adventureResult'); if(!el) return window.print();
  const report=document.createElement('section'); report.className='print-report'; report.innerHTML=`<h1>ITINERA · ${escapeHTML(UI[state.lang].adventureTitle)}</h1>${el.innerHTML}<p class="print-license">Creative Commons CC BY-NC-SA 4.0 · ${LAST_UPDATED}</p>`; document.body.appendChild(report); document.body.classList.add('printing-report'); setTimeout(()=>{window.print(); document.body.classList.remove('printing-report'); report.remove();},80);
}

